config {
  type: "table",
  name: "cln_sales",
  description: "Cleaned and transformed sales data with correct data types.",
  dependencies: [ "stg_sales_raw" ],
  columns: {
    unique_id: "A unique identifier for each sales record.",
    model: "The vehicle model name (cleaned).",
    region: "The standardized region name.",
    units_sold: "The number of units sold (integer).",
    year: "The year of the transaction (integer).",
    revenue_millions: "The revenue in millions (float/numeric)."
  }
}

SELECT
  // Generate a simple unique ID
  GENERATE_UUID() AS unique_id,

  // Basic cleaning (trimming)
  TRIM(model) AS model,

  // Regional standardization (example)
  CASE
    WHEN UPPER(TRIM(region)) IN ('US', 'USA') THEN 'North America'
    WHEN UPPER(TRIM(region)) = 'CA' OR UPPER(TRIM(region)) = 'CANADA' THEN 'North America'
    WHEN UPPER(TRIM(region)) = 'MEXICO' THEN 'North America'
    WHEN UPPER(TRIM(region)) = 'EU' THEN 'Europe'
    WHEN UPPER(TRIM(region)) = 'UK' THEN 'Europe'
    WHEN UPPER(TRIM(region)) = 'ASIA' THEN 'Asia-Pacific'
    WHEN UPPER(TRIM(region)) = 'JAPAN' THEN 'Asia-Pacific'
    WHEN UPPER(TRIM(region)) = 'INDIA' THEN 'Asia-Pacific'
    WHEN UPPER(TRIM(region)) = 'AU' THEN 'Australia'
    WHEN UPPER(TRIM(region)) = 'BRAZIL' THEN 'South America'
    ELSE 'Other'
  END AS standardized_region,

  // Data type casting and basic validation (using SAFE_CAST for robustness)
  SAFE_CAST(TRIM(units_sold) AS INT64) AS units_sold,
  SAFE_CAST(TRIM(year) AS INT64) AS year,
  SAFE_CAST(TRIM(revenue_millions) AS FLOAT64) AS revenue_millions

FROM
  ${ref("stg_sales_raw")}
// Ensure vital fields are not null after casting
WHERE SAFE_CAST(TRIM(units_sold) AS INT64) IS NOT NULL
  AND SAFE_CAST(TRIM(year) AS INT64) IS NOT NULL
  AND SAFE_CAST(TRIM(revenue_millions) AS FLOAT64) IS NOT NULL


