config {
  type: "table",
  name: "agg_region_metrics",
  description: "Summary table of key sales metrics aggregated by standardized region.",
  dependencies: [ "cln_sales" ],
  columns: {
    standardized_region: "The standardized geographic region.",
    total_units_sold: "The total number of units sold in the region.",
    total_revenue_millions: "The total revenue in millions generated in the region.",
    average_revenue_per_unit: "The average revenue in millions per unit sold."
  }
}

SELECT
  standardized_region,
  SUM(units_sold) AS total_units_sold,
  ROUND(SUM(revenue_millions), 2) AS total_revenue_millions,
  // Handle potential division by zero
  CASE
    WHEN SUM(units_sold) > 0 THEN ROUND(SUM(revenue_millions) / SUM(units_sold), 4)
    ELSE 0
  END AS average_revenue_per_unit
FROM
  ${ref("cln_sales")}
GROUP BY
  standardized_region
ORDER BY
  total_revenue_millions DESC

