import React, { useState, useMemo } from 'react';

// Example data structure for warranty claims.
const initialClaimsData = [
  { id: 1, customer: 'John Doe', product: 'Laptop Pro 15', issue: 'Screen flicker', date: '2023-11-20', status: 'Pending' },
  { id: 2, customer: 'Jane Smith', product: 'Smartphone 12', issue: 'Battery drain', date: '2023-11-22', status: 'Approved' },
  { id: 3, customer: 'Michael Brown', product: 'Tablet S', issue: 'Won\'t charge', date: '2023-11-21', status: 'Rejected' },
  { id: 4, customer: 'Emily Davis', product: 'Laptop Pro 15', issue: 'Broken hinge', date: '2023-11-23', status: 'Approved' },
  { id: 5, customer: 'Chris Wilson', product: 'Headphones X', issue: 'Sound cuts out', date: '2023-11-24', status: 'Pending' },
];

const ClaimsTable = () => {
  const [claims, setClaims] = useState(initialClaimsData);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });

  // Filtering Logic
  const filteredClaims = useMemo(() => {
    return claims.filter((claim) => {
      // Convert all values to strings for consistent searching
      const values = Object.values(claim).map((value) => String(value).toLowerCase());
      // Check if any property value matches the search term
      return values.some((value) => value.includes(searchTerm.toLowerCase()));
    });
  }, [claims, searchTerm]);

  // Sorting Logic
  const sortedClaims = useMemo(() => {
    if (!sortConfig.key) return filteredClaims;

    return [...filteredClaims].sort((a, b) => {
      let valA = a[sortConfig.key];
      let valB = b[sortConfig.key];

      // Standardize comparison for different types if needed (e.g., dates)
      // Dates are strings in this example, so string comparison works,
      // but might need conversion for actual date objects.

      if (valA < valB) {
        return sortConfig.direction === 'asc' ? -1 : 1;
      }
      if (valA > valB) {
        return sortConfig.direction === 'asc' ? 1 : -1;
      }
      return 0;
    });
  }, [filteredClaims, sortConfig]);

  const requestSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  // Helper for rendering sort indicator
  const getSortIcon = (columnName) => {
    if (sortConfig.key === columnName) {
      return sortConfig.direction === 'asc' ? ' 🔼' : ' 🔽';
    }
    return ''; // Placeholder or neutral icon
  };

  return (
    <div>
      <h2>Warranty Claims</h2>

      {/* Filter Input */}
      <div>
        <input
          type="text"
          placeholder="Search claims..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Table */}
      <table>
        <thead>
          <tr>
            <th onClick={() => requestSort('id')}>ID {getSortIcon('id')}</th>
            <th onClick={() => requestSort('customer')}>Customer {getSortIcon('customer')}</th>
            <th onClick={() => requestSort('product')}>Product {getSortIcon('product')}</th>
            <th onClick={() => requestSort('issue')}>Issue {getSortIcon('issue')}</th>
            <th onClick={() => requestSort('date')}>Date {getSortIcon('date')}</th>
            <th onClick={() => requestSort('status')}>Status {getSortIcon('status')}</th>
          </tr>
        </thead>
        <tbody>
          {sortedClaims.map((claim) => (
            <tr key={claim.id}>
              <td>{claim.id}</td>
              <td>{claim.customer}</td>
              <td>{claim.product}</td>
              <td>{claim.issue}</td>
              <td>{claim.date}</td>
              <td>{claim.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ClaimsTable;

