   { id: 6, product: 'Keyboard F', customer: 'Fiona White', startDate: '2021-11-01', durationMonths: 12, status: 'Expired' },
];

// Helper function to calculate expiry date
function getExpiryDate(startDateStr, durationMonths) {
    const startDate = new Date(startDateStr);
    const expiryDate = new Date(startDate);
    expiryDate.setMonth(startDate.getMonth() + durationMonths);
    return expiryDate.toISOString().split('T')[0];
}

// Add calculated expiry dates and current status based on today
warranties.forEach(w => {
    w.expiryDate = getExpiryDate(w.startDate, w.durationMonths);
    const today = new Date();
    const expiry = new Date(w.expiryDate);
    w.status = expiry >= today ? 'Active' : 'Expired';
});


// API Endpoint: GET /api/warranties
app.get('/api/warranties', (req, res) => {
  let filteredWarranties = warranties;

  // Apply filters (simple example: product name or status)
  const productFilter = req.query.product;
  const statusFilter = req.query.status;

  if (productFilter) {
    filteredWarranties = filteredWarranties.filter(w =>
      w.product.toLowerCase().includes(productFilter.toLowerCase())
    );
  }

  if (statusFilter && statusFilter !== 'All') {
      filteredWarranties = filteredWarranties.filter(w =>
          w.status === statusFilter
      );
  }

  res.json(filteredWarranties);
});

