// Assuming this component is in a file like WarrantyDashboard.js
// You would need an existing React project and would typically add 'axios' for requests.
// This example uses `fetch`.

import React, { useState, useEffect } from 'react';
import './WarrantyDashboard.css'; // Assume some basic styling

function WarrantyDashboard() {
  const [warranties, setWarranties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [productFilter, setProductFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('All'); // 'All', 'Active', 'Expired'

  useEffect(() => {
    const fetchWarranties = async () => {
      setLoading(true);
      setError(null);
      try {
        let url = 'http://localhost:3001/api/warranties';
        const params = new URLSearchParams();
        if (productFilter) params.append('product', productFilter);
        if (statusFilter && statusFilter !== 'All') params.append('status', statusFilter);

        if(params.toString()){
            url += '?' + params.toString();
        }

        const response = await fetch(url);
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        setWarranties(data);
      } catch (e) {
        setError(e.message);
      } finally {
        setLoading(false);
      }
    };

    fetchWarranties();
  }, [productFilter, statusFilter]); // Re-run when filters change


  if (loading) return <div>Loading warranties...</div>;
  if (error) return <div>Error: {error}</div>;

  return (
    <div className="warranty-dashboard">
      <h1>Warranty Dashboard</h1>

      <div className="filters">
        <label>
          Filter by Product:
          <input
            type="text"
            value={productFilter}
            onChange={(e) => setProductFilter(e.target.value)}
            placeholder="Enter product name"
          />
        </label>
         <label>
          Filter by Status:
          <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Active">Active</option>
            <option value="Expired">Expired</option>
          </select>
        </label>
      </div>

      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Product</th>
            <th>Customer</th>
            <th>Start Date</th>
            <th>Duration (Months)</th>
            <th>Expiry Date</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {warranties.map((warranty) => (
            <tr key={warranty.id}>
              <td>{warranty.id}</td>
              <td>{warranty.product}</td>
              <td>{warranty.customer}</td>
              <td>{warranty.startDate}</td>
              <td>{warranty.durationMonths}</td>
              <td>{warranty.expiryDate}</td>
              <td className={`status-${warranty.status.toLowerCase()}`}>{warranty.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
      {warranties.length === 0 && <p>No warranties found matching the filters.</p>}
    </div>
  );
}

export default WarrantyDashboard;

